#include<bits/stdc++.h>
using namespace std;

const int N = 5005;
vector<int> g[N];
int dfn[N], low[N], cnt, sum;
int color[N], deg[N];
stack<int> st;
int n, m;

void tarjan(int u, int fa) {
    dfn[u] = low[u] = ++cnt;
    st.push(u);

    bool flag = false;
    for(int v : g[u]) {
        if(v == fa && !flag) {
            flag = true;
            continue;
        }

        if(!dfn[v]) {
            tarjan(v, u);
            low[u] = min(low[u], low[v]);
        } else {
            low[u] = min(low[u], dfn[v]);
        }
    }

    if(dfn[u] == low[u]) {
        sum++;
        int x;
        do {
            x = st.top();
            st.pop();
            color[x] = sum;
        } while(x != u);
    }
}

int main() {
    cin >> n >> m;

    for(int i = 1; i <= m; i++) {
        int u, v;
        cin >> u >> v;
        g[u].push_back(v);
        g[v].push_back(u);
    }

    tarjan(1, 0);

    for(int u = 1; u <= n; u++) {
        for(int v : g[u]) {
            if(color[u] != color[v]) {
                deg[color[u]]++;
            }
        }
    }

    int leaf = 0;
    for(int i = 1; i <= sum; i++) {
        if(deg[i] == 1) leaf++;
    }

    cout << (leaf + 1) / 2 << endl;

    return 0;
}
